const items = $input.all();
if (items.length === 0) {
  return [{ json: { isValid: false, error: "Empty input payload" } }];
}
const body = items[0].json;

let isValid = true;
let errorReason = "";

const required = ['scheme_id', 'scheme_name', 'category', 'data'];
for (const field of required) {
  if (body[field] === undefined || body[field] === null) {
    isValid = false;
    errorReason = `Missing required field: ${field}`;
    break;
  }
}

if (isValid) {
  const data = body.data;
  if (!data.nav_history || !Array.isArray(data.nav_history) || !data.holdings || !Array.isArray(data.holdings) || !data.risk_metrics || typeof data.risk_metrics !== 'object') {
    isValid = false;
    errorReason = "Field 'data' must contain nav_history (array), holdings (array), and risk_metrics (object)";
  }
}

return [{
  json: {
    ...body,
    isValid: isValid,
    error: errorReason
  }
}];

const items = $input.all();
const body = items[0].json;
const data = body.data || {};
const navHistory = Array.isArray(data.nav_history) ? data.nav_history : [];

function parseDate(dStr) {
  if (!dStr) return null;
  const parts = String(dStr).split('-');
  if (parts.length === 3 && parts[0].length === 2 && parts[2].length === 4) {
    return new Date(parts[2], parts[1] - 1, parts[0]);
  }
  return new Date(dStr);
}

const historyObj = navHistory.map(item => ({
  date: parseDate(item.date),
  nav: parseFloat(item.nav)
})).filter(item => item.date !== null && !isNaN(item.date.getTime()) && !isNaN(item.nav))
  .sort((a, b) => a.date - b.date);

// --- CAGR ---
let cagr = { cagr_1y: null, cagr_3y: null, cagr_5y: null, cagr_10y: null };
if (historyObj.length >= 20) {
  const endPoint = historyObj[historyObj.length - 1];
  const endNav = endPoint.nav;
  const endDate = endPoint.date;
  const calcCAGR = (years) => {
    const targetTime = endDate.getTime() - (years * 365.25 * 86400000);
    let closest = historyObj[0];
    let minDiff = Math.abs(closest.date.getTime() - targetTime);
    for (let i = 1; i < historyObj.length; i++) {
      const diff = Math.abs(historyObj[i].date.getTime() - targetTime);
      if (diff < minDiff) { minDiff = diff; closest = historyObj[i]; }
    }
    const diffDays = Math.abs(closest.date.getTime() - targetTime) / 86400000;
    if (diffDays > 45) return null;
    const startNav = closest.nav;
    if (startNav <= 0 || endNav <= 0) return null;
    const actualYears = (endDate.getTime() - closest.date.getTime()) / (365.25 * 86400000);
    if (actualYears <= 0.1) return null;
    return Math.pow(endNav / startNav, 1 / actualYears) - 1;
  };
  cagr = { cagr_1y: calcCAGR(1), cagr_3y: calcCAGR(3), cagr_5y: calcCAGR(5), cagr_10y: calcCAGR(10) };
}

// --- Volatility ---
let vol = { annualized_volatility: null, sharpe_ratio: null, max_drawdown: null, total_years_analyzed: null };
if (historyObj.length >= 5) {
  const returns = [];
  for (let i = 1; i < historyObj.length; i++) {
    const prev = historyObj[i - 1].nav;
    const curr = historyObj[i].nav;
    if (prev > 0) returns.push((curr - prev) / prev);
  }
  if (returns.length >= 4) {
    const mean = returns.reduce((a, b) => a + b, 0) / returns.length;
    const variance = returns.reduce((s, r) => s + Math.pow(r - mean, 2), 0) / (returns.length - 1);
    const dailyStd = Math.sqrt(variance);
    const annVol = dailyStd * Math.sqrt(252);
    const startNav = historyObj[0].nav;
    const endNav = historyObj[historyObj.length - 1].nav;
    const startYear = historyObj[0].date.getFullYear() + historyObj[0].date.getMonth() / 12 + historyObj[0].date.getDate() / 365;
    const endYear = historyObj[historyObj.length - 1].date.getFullYear() + historyObj[historyObj.length - 1].date.getMonth() / 12 + historyObj[historyObj.length - 1].date.getDate() / 365;
    const totalYears = endYear - startYear;
    let sharpe = null;
    if (totalYears > 0.1 && startNav > 0 && endNav > 0 && annVol > 0) {
      const annReturn = Math.pow(endNav / startNav, 1 / totalYears) - 1;
      sharpe = (annReturn - 0.065) / annVol;
    }
    let peak = -Infinity, maxDD = 0;
    for (let i = 0; i < historyObj.length; i++) {
      const nav = historyObj[i].nav;
      if (nav > peak) peak = nav;
      const dd = (nav - peak) / peak;
      if (dd < maxDD) maxDD = dd;
    }
    vol = { annualized_volatility: annVol, sharpe_ratio: sharpe, max_drawdown: maxDD, total_years_analyzed: totalYears };
  }
}

// --- Trim holdings to top 15 by weight ---
const holdings = Array.isArray(data.holdings) ? data.holdings : [];
const weightOf = (h) => {
  const w = h.percentage ?? h.weight ?? h.pct ?? h.holding_pct ?? h.allocation;
  const n = parseFloat(w);
  return isNaN(n) ? 0 : n;
};
const topHoldings = holdings.slice().sort((a, b) => weightOf(b) - weightOf(a)).slice(0, 15);

return [{
  json: {
    ...body,
    computed_metrics: { cagr, volatility: vol, nav_points: historyObj.length },
    top_holdings: topHoldings
  }
}];

const items = $input.all();
const errorReason = items[0]?.json?.error || "Unknown validation error";

return [{
  json: {
    success: false,
    error: errorReason
  }
}];

