const navHistory = query.nav_history || [];
if (!Array.isArray(navHistory) || navHistory.length < 2) {
  return JSON.stringify({ error: "Insufficient NAV history data. Must have at least 2 points." });
}

function parseDate(dStr) {
  if (!dStr) return null;
  const parts = dStr.split('-');
  if (parts.length === 3 && parts[0].length === 2 && parts[2].length === 4) {
    return new Date(parts[2], parts[1] - 1, parts[0]);
  }
  return new Date(dStr);
}

const historyObj = navHistory.map(item => {
  return {
    date: parseDate(item.date),
    nav: parseFloat(item.nav)
  };
}).filter(item => item.date !== null && !isNaN(item.date.getTime()) && !isNaN(item.nav))
  .sort((a, b) => a.date - b.date);

if (historyObj.length < 20) {
  return JSON.stringify({ error: "Insufficient valid NAV history records. Minimum 20 records required." });
}

const endPoint = historyObj[historyObj.length - 1];
const endNav = endPoint.nav;
const endDate = endPoint.date;

function calculateCAGRForYears(years) {
  const targetTime = endDate.getTime() - (years * 365.25 * 24 * 60 * 60 * 1000);
  let closestItem = historyObj[0];
  let minDiff = Math.abs(closestItem.date.getTime() - targetTime);

  for (let i = 1; i < historyObj.length; i++) {
    const diff = Math.abs(historyObj[i].date.getTime() - targetTime);
    if (diff < minDiff) {
      minDiff = diff;
      closestItem = historyObj[i];
    }
  }

  const diffDays = Math.abs(closestItem.date.getTime() - targetTime) / (1000 * 60 * 60 * 24);
  if (diffDays > 45) {
    return null;
  }

  const startNav = closestItem.nav;
  if (startNav <= 0 || endNav <= 0) return null;

  const actualYears = (endDate.getTime() - closestItem.date.getTime()) / (365.25 * 24 * 60 * 60 * 1000);
  if (actualYears <= 0.1) return null;

  const cagr = Math.pow(endNav / startNav, 1 / actualYears) - 1;
  return cagr;
}

const result = {
  cagr_1y: calculateCAGRForYears(1),
  cagr_3y: calculateCAGRForYears(3),
  cagr_5y: calculateCAGRForYears(5),
  cagr_10y: calculateCAGRForYears(10)
};

return JSON.stringify(result);

const navHistory = query.nav_history || [];
if (!Array.isArray(navHistory) || navHistory.length < 5) {
  return JSON.stringify({ error: "Insufficient NAV history data for volatility analysis." });
}

function parseDate(dStr) {
  if (!dStr) return null;
  const parts = dStr.split('-');
  if (parts.length === 3 && parts[0].length === 2 && parts[2].length === 4) {
    return new Date(parts[2], parts[1] - 1, parts[0]);
  }
  return new Date(dStr);
}

const historyObj = navHistory.map(item => {
  return {
    date: parseDate(item.date),
    nav: parseFloat(item.nav)
  };
}).filter(item => item.date !== null && !isNaN(item.date.getTime()) && !isNaN(item.nav))
  .sort((a, b) => a.date - b.date);

if (historyObj.length < 5) {
  return JSON.stringify({ error: "Insufficient valid NAV history data." });
}

const returns = [];
for (let i = 1; i < historyObj.length; i++) {
  const prevNav = historyObj[i - 1].nav;
  const currNav = historyObj[i].nav;
  if (prevNav > 0) {
    returns.push((currNav - prevNav) / prevNav);
  }
}

if (returns.length < 4) {
  return JSON.stringify({ error: "Insufficient daily returns." });
}

const meanReturn = returns.reduce((a, b) => a + b, 0) / returns.length;
const variance = returns.reduce((sum, r) => sum + Math.pow(r - meanReturn, 2), 0) / (returns.length - 1);
const dailyStdDev = Math.sqrt(variance);
const annualizedVolatility = dailyStdDev * Math.sqrt(252);

const startNav = historyObj[0].nav;
const endNav = historyObj[historyObj.length - 1].nav;
const startYear = historyObj[0].date.getFullYear() + (historyObj[0].date.getMonth() / 12) + (historyObj[0].date.getDate() / 365);
const endYear = historyObj[historyObj.length - 1].date.getFullYear() + (historyObj[historyObj.length - 1].date.getMonth() / 12) + (historyObj[historyObj.length - 1].date.getDate() / 365);
const totalYears = endYear - startYear;

let SharpeRatio = null;
if (totalYears > 0.1 && startNav > 0 && endNav > 0 && annualizedVolatility > 0) {
  const annualizedReturn = Math.pow(endNav / startNav, 1 / totalYears) - 1;
  const riskFreeRate = 0.065;
  SharpeRatio = (annualizedReturn - riskFreeRate) / annualizedVolatility;
}

let peak = -Infinity;
let maxDrawdown = 0;
for (let i = 0; i < historyObj.length; i++) {
  const nav = historyObj[i].nav;
  if (nav > peak) {
    peak = nav; 
  }
  const drawdown = (nav - peak) / peak;
  if (drawdown < maxDrawdown) {
    maxDrawdown = drawdown;
  }
}

const result = {
  annualized_volatility: annualizedVolatility,
  sharpe_ratio: SharpeRatio,
  max_drawdown: maxDrawdown,
  total_years_analyzed: totalYears
};

return JSON.stringify(result);
